package gcl65_2.Session6;

// https://leetcode.com/problems/find-all-anagrams-in-a-string/

import java.util.ArrayList;
import java.util.HashSet;
import java.util.List;
import java.util.Set;

public class FindAllAnagramsInAString {

    public static void main(String[] args) {
        System.out.println(new FindAllAnagramsInAString().findAnagrams("cbaebabacd", "abc"));
        System.out.println(new FindAllAnagramsInAString().findAnagrams("abab", "ab"));
        System.out.println(new FindAllAnagramsInAString().findAnagrams("baa", "aa"));
        System.out.println(new FindAllAnagramsInAString().findAnagrams("aaaaaaaaaa", "aaaaaaaaaaaaa"));

//        BELOW TIMEOUTS
//        System.out.println(new FindAllAnagramsInAString().findAnagrams("", "yqrbgjdwtcaxzsnifvhmou"));
    }

    public List<Integer> findAnagrams(String s, String p) {
        List<Integer> result = new ArrayList<>();
        if (s.length() < p.length()) {
            return result;
        }
        Set<String> anagrams = new HashSet<>();
        findAnagrams(s, p.toCharArray(), p.length(), 0, "", anagrams, result);
        return result;
    }

    private void findAnagrams(String s, char[] chars, int n, int i, String anagram, Set<String> anagrams, List<Integer> result) {
        // base case
        if (i == n) {
            if (!anagrams.contains(anagram)) {
                anagrams.add(anagram);
                int idx = s.indexOf(anagram, 0);
                while (idx > -1) {
                    result.add(idx);
                    idx = s.indexOf(anagram, idx + 1);
                }
            }
            return;
        }

        // recursive case
        for (int j = i; j < n; j++) {
            swap(chars, i, j);
            findAnagrams(s, chars, n, i + 1, anagram + chars[i], anagrams, result);
            swap(chars, i, j); // backtracking
        }
    }

    private void swap(char[] chars, int i, int j) {
        char t = chars[i];
        chars[i] = chars[j];
        chars[j] = t;
    }

}
